'use strict';
/**
 * REGRESSION — FRG-184
 * Verifies that each character queries the LLM API and receives valid decisions.
 */
const { test, expect } = require('@playwright/test');
const { waitForEngine } = require('../helpers');

test.describe('Regression: AI decision-making via /api/llm', () => {
  test('each character sends a POST to /api/llm on page load', async ({ page }) => {
    const llmRequests = [];

    page.on('request', req => {
      if (req.url().includes('/api/llm') && req.method() === 'POST') {
        llmRequests.push(req);
      }
    });

    await page.goto('/');
    await waitForEngine(page);

    // All 3 characters fire immediately (timer starts at 0)
    await page.waitForTimeout(8000); // allow time for all 3 requests

    expect(llmRequests.length).toBeGreaterThanOrEqual(3);
  });

  test('LLM request body includes character name, position, and nearby objects', async ({ page }) => {
    const bodies = [];

    page.on('request', req => {
      if (req.url().includes('/api/llm') && req.method() === 'POST') {
        try {
          bodies.push(JSON.parse(req.postData() || '{}'));
        } catch { /* ignore */ }
      }
    });

    await page.goto('/');
    await waitForEngine(page);
    await page.waitForTimeout(8000);

    expect(bodies.length).toBeGreaterThanOrEqual(3);

    for (const body of bodies) {
      // System prompt includes a character name
      expect(body.system).toMatch(/You are (Maple|Sol|Nyx)/);
      // Includes mood and energy
      expect(body.system).toMatch(/mood.*\/100.*energy.*\/100/);
      // User message includes sim time, tile position, nearby objects
      const userContent = body.messages?.[0]?.content || '';
      expect(userContent).toMatch(/Sim time:/);
      expect(userContent).toMatch(/You are at tile/);
      expect(userContent).toMatch(/Nearby objects:/);
      // max_tokens set to 256
      expect(body.max_tokens).toBe(256);
    }
  });

  test('LLM responses are valid JSON with action field', async ({ page }) => {
    const responses = [];

    page.on('response', async res => {
      if (res.url().includes('/api/llm') && res.request().method() === 'POST') {
        try {
          const json = await res.json();
          // Extract content from API response (Anthropic/OpenAI shape)
          const text = json?.content?.[0]?.text
                    ?? json?.choices?.[0]?.message?.content;
          if (text) responses.push(JSON.parse(text));
        } catch { /* ignore */ }
      }
    });

    await page.goto('/');
    await waitForEngine(page);
    await page.waitForTimeout(10000);

    expect(responses.length).toBeGreaterThanOrEqual(3);

    for (const decision of responses) {
      expect(decision).toHaveProperty('action');
      expect(['move', 'interact', 'idle']).toContain(decision.action);

      if (decision.action === 'move') {
        expect(decision).toHaveProperty('targetTile');
        expect(typeof decision.targetTile.tx).toBe('number');
        expect(typeof decision.targetTile.ty).toBe('number');
      }
      if (decision.action === 'interact') {
        expect(decision).toHaveProperty('targetId');
        expect(typeof decision.targetId).toBe('string');
      }
    }
  });

  test('each character only receives one decision per 30s interval', async ({ page }) => {
    const byChar = new Map();

    page.on('request', req => {
      if (req.url().includes('/api/llm') && req.method() === 'POST') {
        try {
          const body = JSON.parse(req.postData() || '{}');
          const match = (body.system || '').match(/You are (Maple|Sol|Nyx)/);
          if (match) {
            const name = match[1];
            byChar.set(name, (byChar.get(name) || 0) + 1);
          }
        } catch { /* ignore */ }
      }
    });

    await page.goto('/');
    await waitForEngine(page);

    // Wait well under one interval (< 30 s) — each char should have exactly 1 request
    await page.waitForTimeout(10000);

    expect(byChar.size).toBe(3); // All 3 characters sent a request
    for (const [name, count] of byChar) {
      expect(count, `${name} sent ${count} requests (expected 1 in first 10 s)`).toBe(1);
    }
  });

  test('/api/llm endpoint returns HTTP 200 with valid JSON', async ({ page }) => {
    const statuses = [];

    page.on('response', res => {
      if (res.url().includes('/api/llm')) {
        statuses.push(res.status());
      }
    });

    await page.goto('/');
    await waitForEngine(page);
    await page.waitForTimeout(8000);

    expect(statuses.length).toBeGreaterThanOrEqual(3);
    for (const status of statuses) {
      expect(status).toBe(200);
    }
  });
});

