test('character action transitions: idle → walking → interacting or idle', async ({ page }) => {
  // Observe a character through a full walk cycle.
  // Characters often go walking → interacting (wander timer fires activity on arrival)
  // so we accept either interacting or idle as the post-walk state.
  const walkStartState = await pollEngineState(
    page,
    state => state.characters.some(c => c.action === 'walking'),
    15_000
  );
  const charName = walkStartState.characters.find(c => c.action === 'walking').name;

  // Wait for that character to stop walking (arrive at destination)
  const arrivedState = await pollEngineState(
